VALUES
  ('disabled-6f0ba476-moex-00591', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲乙二人為下列各種法律行為，何種行為應適用客觀規範解釋原則，以客 觀能理解之意思為準，無須與表意人之內心真意一致？', '["甲乙訂立買賣契約，甲意思表示錯誤", "甲乙通謀虛偽意思表示，為土地所有權之移轉登記", "甲無僱用乙為秘書之意思，卻對外宣稱僱用乙為秘書，乙明知甲之真意", "甲將其所有之A汽車，以每日1,000元之價格出租給乙，租賃契約生效 後，甲誤取B車交給乙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00592', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者為附始期之法律行為？', '["甲乙約定下次國慶日一同去購買紀念酒", "甲乙約定誰先結婚，應送對方金筆1枝", "甲聘任乙為總經理，約定聘期於3日後生效", "甲聘任乙為總經理，約定試用期3個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00593', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲於所有之A地，自建房屋1棟，左側蓋有車庫1間，屋內之書房放有臺 灣檜木之書桌1張，該書桌有2個抽屜，書桌上放有手機1支與其鬆脫之 電池1個，地上放有英國製之落地燈1座，並配以蕾絲燈罩1頂。下列敘 述，何者錯誤？', '["車庫為房屋之從物", "抽屜為書桌之從物", "燈罩為落地燈之從物", "手機之電池為手機之從物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00594', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '代理人所為之代理行為未經本人許諾或非專為履行債務時，而為雙方代理 時，其所為之代理行為效力如何？', '["得撤回", "得撤銷", "效力未定", "得解除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00595', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於民法年齡計算之敘述，何者錯誤？', '["年齡自出生之日起算", "出生之年無法確定時，得申請戶政機關決定之", "出生之月、日無從確定時，推定其為7月1日出生", "知出生之月，而不知出生之日者，推定其為該月15日出生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00596', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '以動產租賃為營業者，因租賃而生之租金請求權，該請求權之消滅時效期 間為幾年？', '["2年", "5年", "10年", "15年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00597', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於清償之敘述，何者正確？', '["債務人若向無受領權人為給付，絕不生清償效力", "債務人之給付，雖不合債務本旨，仍生清償效力", "債之清償，絕不得由第三人為之", "雖非債權人，卻係債權準占有人，而受領債務人之給付，仍得發生清償 效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00598', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於契約成立之敘述，何者正確？', '["除非當事人間特別約定，否則契約不可因交錯要約而成立", "民法第161條第1項規定，依習慣承諾無須通知者，在相當時期內，有 可認為承諾之事實時，其契約為成立，故當事人間不得特別約定拒絕承 諾時，應行通知要約人", "報社送報至完全行為能力人某甲之住宅而為要約，甲取而閱之，契約即 成立", "要約人要約當時預先聲明承諾無須通知者，因相對人無受該聲明拘束之 義務，故即使在相當時期內，有可認為承諾之事實時，其契約仍不成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00599', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者非屬當事人縱使無過失仍應負責之情形？', '["受寄人保管寄託物，其受有報酬者，應負之責任", "旅店或其他供客人住宿為目的之場所主人，對於客人所攜帶物品之毀 損、喪失，應負之責任", "飲食店、浴堂或其他相類場所之主人，對於客人所攜帶通常物品之毀損、 喪失，應負之責任", "無因管理人違反本人明示或可得推知之意思，而為事務之管理者，對於 因其管理所生之損害，應負之責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00600', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '定作人甲請承攬人乙建造圍牆，工作甫完成之際，因暴雨造成重大水患， 沖壞圍牆。下列敘述，何者錯誤？', '["工作物毀損之危險，於甲受領前，由乙負擔", "於甲受領前，工作物滅失者，乙喪失報酬請求權", "若甲有受領遲延時，工作物滅失後，甲仍須給付報酬", "承攬契約，因不可歸責於雙方當事人之事由，致乙不能完成工作，承攬 契約失其效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
